mapper.select:
SELECT SP.TBL_SO_P_ID as tblSoPId, SM.TBL_SO_M_ID as tblSoMId, SM.CMPY_CD as cmpyCd, SM.AGNT_CD as agntCd, AM.AGNT_NM as agntNm, SM.SO_TYPE as soType, DBO.F_COL_NM(SM.CMPY_CD, 'COMM', 'SO_ORDR_TYPE', SM.SO_TYPE) as soTypeNm, SM.SO_STAT_CD as soStatCd, DBO.F_COL_NM(SM.CMPY_CD, 'COMM', 'SO_STAT_CD', SM.SO_STAT_CD) as soStatNm, DM.DC_NM as dcNm, SM.DLVY_CNFM_DT as dlvyCnfmDt, SM.GI_LIFT_DT as giLiftDt, CONVERT(VARCHAR(10), IM.UPDT_TIME, 112) as liftCmplDt, SM.SO_NO as soNo, SM.REF_SO_NO as refSoNo, SM.ACPT_ER as acptEr, IM.PALT_NOXX as paltNoxx, UM.USER_NM as instEr, DBO.F_COL_NM(SM.CMPY_CD, 'COMM', 'DLVY_STAT_CD', IM.DLVY_STAT_CD) as dlvyStatNm, SP.PROD_CD as cprodCd, SP.PROD_NM as cprodNm, SP.QTY as cqty, SP.COURIER_CD as courierCd, SP.COURIER_NM as courierNm, SP.WAYBILL_NO as waybillNo, SP.OUTBOUND_DT as outboundDt, SP.OUTBOUND_USER as outboundUser, PM.MTO_YN as mtoYn, SP.PROD_CD as mtrlCd FROM TBL_SO_M AS SM WITH (NOLOCK) INNER JOIN TBL_SO_P AS SP WITH (NOLOCK) ON SM.TBL_SO_M_ID = SP.TBL_SO_M_ID LEFT OUTER JOIN TBL_AGENCY_M AS AM WITH (NOLOCK) ON SM.CMPY_CD = AM.CMPY_CD AND SM.AGNT_CD = AM.AGNT_CD LEFT OUTER JOIN TBL_LGST_DC_M AS DM WITH (NOLOCK) ON SM.DC_CD = DM.DC_CD LEFT OUTER JOIN TBL_INST_MOBILE_M AS IM WITH (NOLOCK) ON SM.TBL_SO_M_ID = IM.TBL_SO_M_ID LEFT OUTER JOIN TBL_USER_M AS UM WITH (NOLOCK) ON IM.EXEC_USER_M_ID = UM.TBL_USER_M_ID LEFT OUTER JOIN TBL_MTRL_M AS PM WITH (NOLOCK) ON SP.PROD_CD = PM.MTRL_CD AND SM.AGNT_CD = PM.AGNT_CD WHERE 1=1 AND (SM.SO_STAT_CD = '2000' OR SM.SO_STAT_CD = '2500' OR SM.SO_STAT_CD = '3000' OR SM.SO_STAT_CD = '3500' OR SM.SO_STAT_CD = '4000' OR SM.SO_STAT_CD = '5000' OR SM.SO_STAT_CD = '5500' OR SM.SO_STAT_CD = '6000') AND SP.USE_YN = 'Y' AND SM.SO_TYPE IN ('1000', '3100', '4000', '5000', '6000', '9901', '9902', '9905', '9908') AND ISNULL(PM.MTO_YN, 'N') = 'N' AND SP.OUTBOUND_DT IS NULL
AND SM.CMPY_CD = #{cmpyCd}
AND SM.ORDR_INPT_DT >= #{fromDt}
AND SM.GI_LIFT_DT >= #{fromDt}
AND SM.DLVY_CNFM_DT >= #{fromDt}
AND SM.ORDR_INPT_DT >= #{fromDt}
AND SM.ORDR_INPT_DT <= #{toDt}
AND SM.GI_LIFT_DT <= #{toDt}
AND SM.DLVY_CNFM_DT <= #{toDt}
AND SM.ORDR_INPT_DT <= #{toDt}
AND SM.AGNT_CD IN
#{agnt}
AND SM.DC_CD IN
#{dc}
AND SM.SO_NO IN
#{so}
AND SM.SO_TYPE IN
#{type}
AND SM.ACPT_ER LIKE '%' + #{acptNm} + '%'
AND SP.PROD_CD IN
#{prod}
AND SP.PROD_NM LIKE '%' + #{prodNm} + '%'
ORDER BY SM.DLVY_CNFM_DT, SM.SO_NO

SELECT 
    TBL_MTRL_M_ID as tblMtrlMId,
    ISNULL(CURRENT_QUANTITY, 0) as currentQty
FROM TBL_MTRL_M WITH (NOLOCK)
WHERE CMPY_CD = #{cmpyCd}
AND AGNT_CD = #{agntCd}
AND MTRL_CD = #{mtrlCd}
AND MTO_YN = 'N'

mapper.update:
UPDATE TBL_MTRL_M
SET YONGIN_CURRENT_QUANTITY = ISNULL(YONGIN_CURRENT_QUANTITY, 0) - #{qty},
    CURRENT_QUANTITY = ISNULL(CURRENT_QUANTITY, 0) - #{qty},
    UPDT_TIME = GETDATE(),
    UPDT_USER = #{processUser}
WHERE CMPY_CD = #{cmpyCd}
AND AGNT_CD = #{agntCd}
AND MTRL_CD = #{mtrlCd}
AND MTO_YN = 'N'

UPDATE TBL_SO_M
SET SO_STAT_CD = '9999',
    UPDT_TIME = GETDATE(),
    UPDT_USER = #{processUser}
WHERE TBL_SO_M_ID = #{tblSoMId}
